371→    @Transactional(propagation = Propagation.SUPPORTS)
372→    public RunFrame prepareRqdRunFrame(VirtualProc proc, DispatchFrame frame) {
373→        int threads = proc.coresReserved / 100;
374→        if (threads < 1) {
375→            threads = 1;
376→        }
377→
378→        int frameNumber = Integer.valueOf(frame.name.substring(0, frame.name.indexOf("-")));
379→        String zFrameNumber = String.format("%04d", frameNumber);
380→
381→        FrameSet fs = new FrameSet(frame.range);
382→        int startFrameIndex = fs.index(frameNumber);
383→        String frameSpec = fs.getChunk(startFrameIndex, frame.chunkSize);
384→
385→        FrameSet chunkFrameSet = new FrameSet(frameSpec);
386→        int chunkEndFrame = chunkFrameSet.get(chunkFrameSet.size() - 1);
387→
388→        RunFrame.Builder builder = RunFrame.newBuilder().setShot(frame.shot).setShow(frame.show)
389→                .setUserName(frame.owner).setLogDir(frame.logDir).setJobId(frame.jobId)
390→                .setJobName(frame.jobName).setFrameId(frame.id).setFrameName(frame.name)
391→                .setLayerId(frame.getLayerId()).setResourceId(proc.getProcId())
392→                .setNumCores(proc.coresReserved).setNumGpus(proc.gpusReserved)
393→                .setStartTime(System.currentTimeMillis()).setIgnoreNimby(proc.isLocalDispatch)
394→                .setOs(proc.os).setSoftMemoryLimit(frame.softMemoryLimit).setLokiUrl(frame.lokiURL)
395→                .setHardMemoryLimit(frame.hardMemoryLimit)
396→                .putAllEnvironment(jobDao.getEnvironment(frame))
397→                .putAllEnvironment(layerDao.getLayerEnvironment(frame)).putEnvironment("CUE3", "1")
398→                .putEnvironment("CUE_THREADS", String.valueOf(threads))
399→                .putEnvironment("CUE_MEMORY", String.valueOf(proc.memoryReserved))
400→                .putEnvironment("CUE_GPUS", String.valueOf(proc.gpusReserved))
401→                .putEnvironment("CUE_GPU_MEMORY", String.valueOf(proc.gpuMemoryReserved))
402→                .putEnvironment("CUE_LOG_PATH", frame.logDir)
403→                .putEnvironment("CUE_RANGE", frame.range)
404→                .putEnvironment("CUE_CHUNK", String.valueOf(frame.chunkSize))
405→                .putEnvironment("CUE_IFRAME", String.valueOf(frameNumber))
406→                .putEnvironment("CUE_LAYER", frame.layerName)
407→                .putEnvironment("CUE_JOB", frame.jobName).putEnvironment("CUE_FRAME", frame.name)
408→                .putEnvironment("CUE_SHOW", frame.show).putEnvironment("CUE_SHOT", frame.shot)
409→                .putEnvironment("CUE_USER", frame.owner).putEnvironment("CUE_JOB_ID", frame.jobId)
410→                .putEnvironment("CUE_LAYER_ID", frame.layerId)
411→                .putEnvironment("CUE_FRAME_ID", frame.id)
412→                .putEnvironment("CUE_THREADABLE", frame.threadable ? "1" : "0")
413→                .setCommand(frame.command.replaceAll("#ZFRAME#", zFrameNumber)
414→                        .replaceAll("#IFRAME#", String.valueOf(frameNumber))
415→                        .replaceAll("#FRAME_START#", String.valueOf(frameNumber))
416→                        .replaceAll("#FRAME_END#", String.valueOf(chunkEndFrame))
417→                        .replaceAll("#FRAME_CHUNK#", String.valueOf(frame.chunkSize))
418→                        .replaceAll("#LAYER#", frame.layerName).replaceAll("#JOB#", frame.jobName)
419→                        .replaceAll("#FRAMESPEC#", frameSpec).replaceAll("#FRAME#", frame.name));
420→        /*
421→         * The special command tokens above (#ZFRAME# and others) are provided to the user in
422→         * cuesubmit. see: cuesubmit/cuesubmit/Constants.py Update the Constant.py file when
423→         * updating tokens here, they will appear in the cuesubmit tooltip popup.
424→         */
425→
426→        frame.uid.ifPresent(builder::setUid);
427→
428→        return builder.build();
429→    }
