488→    @Transactional(propagation = Propagation.REQUIRED)
489→    public void unbookProc(VirtualProc proc, String reason) {
490→        if (proc == null) {
491→            return;
492→        }
493→        if (proc.isNew()) {
494→            return;
495→        }
496→        proc.unbooked = true;
497→        procDao.deleteVirtualProc(proc);
498→        publishProcEvent(EventType.PROC_UNBOOKED, proc);
499→        DispatchSupport.unbookedProcs.getAndIncrement();
500→        logger.info(proc + " " + reason);
501→
502→        /*
503→         * Remove the local dispatch record if it has gone inactive.
504→         */
505→        if (proc.isLocalDispatch) {
506→            try {
507→                bookingManager.removeInactiveLocalHostAssignment(
508→                        bookingDao.getLocalJobAssignment(proc.getHostId(), proc.getJobId()));
509→            } catch (EmptyResultDataAccessException e) {
510→                // Eat the exception.
511→            }
512→        }
513→    }
