515→    @Override
516→    @Transactional(propagation = Propagation.NOT_SUPPORTED)
517→    public void lostProc(VirtualProc proc, String reason, int exitStatus) {
518→        long numCleared = clearedProcs.incrementAndGet();
519→
520→        unbookProc(proc, "proc " + proc.getName() + " is #" + numCleared + " cleared: " + reason);
521→
522→        if (proc.frameId != null) {
523→            FrameInterface f = frameDao.getFrame(proc.frameId);
524→            /*
525→             * Set the checkpoint state to disabled before stopping the the frame because it will go
526→             * to the checkpoint state. This is not desirable when we're clearing off processes that
527→             * were lost due to a machine crash.
528→             */
529→            frameDao.updateFrameCheckpointState(f, CheckpointState.DISABLED);
530→            /*
531→             * If the proc has a frame, stop the frame. Frames can only be stopped that are running.
532→             */
533→            if (frameDao.updateFrameStopped(f, FrameState.WAITING, exitStatus)) {
534→                updateUsageCounters(proc, exitStatus);
535→            }
536→            /*
537→             * If the frame is not running, check if frame is in dead state, frames that died due to
538→             * host going down should be put back into WAITING status.
539→             */
540→            else {
541→                FrameDetail frameDetail = frameDao.getFrameDetail(f);
542→                if ((frameDetail.state == FrameState.DEAD)
543→                        && (Dispatcher.EXIT_STATUS_DOWN_HOST == exitStatus)) {
544→                    if (frameDao.updateFrameHostDown(f)) {
545→                        logger.info("update frame " + f.getFrameId()
546→                                + "to WAITING status for down host");
547→                    }
548→                }
549→            }
550→        } else {
551→            logger.info("Frame ID is NULL, not updating Frame state");
552→        }
553→    }
