 25→public class DispatchQueue implements QueueHealthCheck {
 26→
 27→    private int healthThreshold;
 28→    private int minUnhealthyPeriodMin;
 29→    private int queueCapacity;
 30→    private int corePoolSize;
 31→    private int maxPoolSize;
 32→
 33→    private static final Logger logger = LogManager.getLogger("HEALTH");
 34→    private String name = "Default";
 35→    private HealthyThreadPool healthyDispatchPool;
 36→
 37→    public DispatchQueue(String name, int healthThreshold, int minUnhealthyPeriodMin,
 38→            int queueCapacity, int corePoolSize, int maxPoolSize) {
 39→        this.name = name;
 40→        this.healthThreshold = healthThreshold;
 41→        this.minUnhealthyPeriodMin = minUnhealthyPeriodMin;
 42→        this.queueCapacity = queueCapacity;
 43→        this.corePoolSize = corePoolSize;
 44→        this.maxPoolSize = maxPoolSize;
 45→        initThreadPool();
 46→    }
 47→
 48→    public void initThreadPool() {
 49→        healthyDispatchPool = new HealthyThreadPool(name, healthThreshold, minUnhealthyPeriodMin,
 50→                queueCapacity, corePoolSize, maxPoolSize);
 51→    }
 52→
 53→    public void shutdownUnhealthy() {
 54→        try {
 55→            if (!healthyDispatchPool.shutdownUnhealthy()) {
 56→                logger.warn("DispatchQueue_" + name
 57→                        + ": Unhealthy queue terminated, starting a new one");
 58→                initThreadPool();
 59→            }
 60→        } catch (InterruptedException e) {
 61→            // TODO: evaluate crashing the whole springbook context here
 62→            // to force a container restart cycle
 63→            logger.error("DispatchQueue_" + name + ":Failed to restart DispatchThreadPool", e);
 64→        }
 65→    }
 66→
 67→    public boolean isHealthy() {
 68→        return healthyDispatchPool.healthCheck();
 69→    }
 70→
 71→    public void execute(KeyRunnable r) {
 72→        healthyDispatchPool.execute(r);
 73→    }
 74→
 75→    public long getRejectedTaskCount() {
 76→        return healthyDispatchPool.getRejectedTaskCount();
 77→    }
 78→
 79→    public void shutdown() {
 80→        healthyDispatchPool.shutdown();
 81→    }
 82→
 83→    public int getSize() {
 84→        return healthyDispatchPool.getQueue().size();
 85→    }
 86→
 87→    public int getRemainingCapacity() {
 88→        return healthyDispatchPool.getQueue().remainingCapacity();
 89→    }
 90→
 91→    public int getActiveCount() {
 92→        return healthyDispatchPool.getActiveCount();
 93→    }
 94→
 95→    public long getCompletedTaskCount() {
 96→        return healthyDispatchPool.getCompletedTaskCount();
 97→    }
 98→
 99→}
