 36→    private static final int BASE_SLEEP_TIME_MILLIS = 300;
 37→
 38→    private static final Logger logger = LogManager.getLogger("HEALTH");
 39→    private HealthyThreadPool healthyThreadPool;
 40→
 41→    public BookingQueue(int healthThreshold, int minUnhealthyPeriodMin, int queueCapacity,
 42→            int corePoolSize, int maxPoolSize) {
 43→        this.healthThreshold = healthThreshold;
 44→        this.minUnhealthyPeriodMin = minUnhealthyPeriodMin;
 45→        this.queueCapacity = queueCapacity;
 46→        this.corePoolSize = corePoolSize;
 47→        this.maxPoolSize = maxPoolSize;
 48→        initThreadPool();
 49→    }
 50→
 51→    public void initThreadPool() {
 52→        healthyThreadPool =
 53→                new HealthyThreadPool("BookingQueue", healthThreshold, minUnhealthyPeriodMin,
 54→                        queueCapacity, corePoolSize, maxPoolSize, BASE_SLEEP_TIME_MILLIS);
 55→    }
 56→
 57→    public void shutdownUnhealthy() {
 58→        try {
 59→            if (!healthyThreadPool.shutdownUnhealthy()) {
 60→                logger.warn("BookingQueue: Unhealthy queue terminated, starting a new one");
 61→                initThreadPool();
 62→            }
 63→        } catch (InterruptedException e) {
 64→            // TODO: evaluate crashing the whole springbook context here
 65→            // to force a container restart cycle
 66→            logger.error("Failed to restart BookingThreadPool", e);
 67→        }
 68→    }
