169→    public void handleHostReport(HostReport report, boolean isBoot) {
170→        long startTime = System.currentTimeMillis();
171→        try {
172→            // Record Prometheus metric for host report
173→            if (prometheusMetrics != null) {
174→                String facility = report.getHost().getFacility();
175→                prometheusMetrics.recordHostReport(facility != null ? facility : "unknown");
176→            }
177→
178→            long swapOut = 0;
179→            if (report.getHost().getAttributesMap().containsKey("swapout")) {
180→                swapOut = Integer.parseInt(report.getHost().getAttributesMap().get("swapout"));
181→                if (swapOut > 0)
182→                    logger.info(report.getHost().getName() + " swapout: "
183→                            + report.getHost().getAttributesMap().get("swapout"));
184→            }
185→
186→            DispatchHost host;
187→            RenderHost rhost = report.getHost();
188→            try {
189→                host = hostManager.findDispatchHost(rhost.getName());
190→                hostManager.setHostStatistics(host, rhost.getTotalMem(), rhost.getFreeMem(),
191→                        rhost.getTotalSwap(), rhost.getFreeSwap(), rhost.getTotalMcp(),
192→                        rhost.getFreeMcp(), rhost.getTotalGpuMem(), rhost.getFreeGpuMem(),
193→                        rhost.getLoad(), new Timestamp(rhost.getBootTime() * 1000l),
194→                        rhost.getAttributesMap().get("SP_OS"));
195→
196→                // Both logics are conflicting, only change hardware state if
197→                // there was no need for a tempDirStorage state change
198→                if (!changeStateForTempDirStorage(host, report.getHost())) {
199→                    changeHardwareState(host, report.getHost().getState(), isBoot);
200→                }
201→                changeNimbyState(host, report.getHost());
202→
203→                /**
204→                 * This should only happen at boot time or it will fight with the dispatcher over
205→                 * row locks.
206→                 */
207→                if (isBoot) {
208→                    hostManager.setHostResources(host, report);
209→
210→                    // Update host tags during boot to ensure they're current
211→                    hostManager.updateHostTags(host, report.getHost());
212→                }
213→
214→                dispatchSupport.determineIdleCores(host, report.getHost().getLoad());
215→            } catch (DataAccessException dae) {
216→                logger.info(
217→                        "Unable to find host " + rhost.getName() + "," + dae + " , creating host.");
218→                // TODO: Skip adding it if the host name is over 30 characters
219→
220→                host = hostManager.createHost(report);
221→            } catch (Exception e) {
222→                logger.warn("Error processing HostReport, " + e);
223→                return;
224→            }
225→
226→            /*
227→             * Verify all the frames in the report are valid. Frames that are not valid are removed.
228→             */
229→            List<RunningFrameInfo> runningFrames = verifyRunningFrameInfo(report);
230→
231→            /*
232→             * Updates memory usage for the proc, frames, jobs, and layers. And LLU time for the
233→             * frames.
234→             */
235→            updateMemoryUsageAndLluTime(runningFrames);
236→
237→            /*
238→             * kill frames that have over run.
239→             */
240→            killTimedOutFrames(runningFrames, report.getHost().getName());
241→
242→            /*
243→             * Prevent OOM (Out-Of-Memory) issues on the host and manage frame reserved memory
244→             */
245→            handleMemoryUsage(host, report.getHost(), runningFrames);
246→
247→            /*
248→             * The checks are done in order of least CPU intensive to most CPU intensive, saving
249→             * checks that hit the DB for last.
250→             *
251→             * These are done so we don't populate the booking queue with a bunch of hosts that
252→             * can't be booked.
253→             */
254→            String msg = null;
255→            boolean hasLocalJob = bookingManager.hasLocalHostAssignment(host);
256→            int coresToReserve =
257→                    host.handleNegativeCoresRequirement(Dispatcher.CORE_POINTS_RESERVED_MIN);
258→
259→            if (hasLocalJob) {
260→                List<LocalHostAssignment> lcas = bookingManager.getLocalHostAssignment(host);
261→                for (LocalHostAssignment lca : lcas) {
262→                    bookingManager.removeInactiveLocalHostAssignment(lca);
263→                }
264→            }
265→            long memReservedMin =
266→                    env.getRequiredProperty("dispatcher.memory.mem_reserved_min", Long.class);
267→
268→            if (!isTempDirStorageEnough(report.getHost().getTotalMcp(),
269→                    report.getHost().getFreeMcp(), host.getOs())) {
270→                msg = String.format(
271→                        "%s doesn't have enough free space in the temporary directory (mcp), %dMB",
272→                        host.name, (report.getHost().getFreeMcp() / 1024));
273→            } else if (coresToReserve <= 0
274→                    || host.idleCores < Dispatcher.CORE_POINTS_RESERVED_MIN) {
275→                msg = String.format("%s doesn't have enough idle cores, %d needs %d", host.name,
276→                        host.idleCores, Dispatcher.CORE_POINTS_RESERVED_MIN);
277→            } else if (host.idleMemory < memReservedMin) {
278→                msg = String.format("%s doesn't have enough idle memory, %d needs %d", host.name,
279→                        host.idleMemory, memReservedMin);
280→            } else if (report.getHost().getFreeMem() < CueUtil.MB512) {
281→                msg = String.format("%s doesn't have enough free system mem, %d needs %d",
282→                        host.name, report.getHost().getFreeMem(), memReservedMin);
283→            } else if (!host.hardwareState.equals(HardwareState.UP)) {
284→                msg = host + " is not in the Up state.";
285→            } else if (host.lockState.equals(LockState.LOCKED)) {
286→                msg = host + " is locked.";
287→            } else if (report.getHost().getNimbyLocked()) {
288→                if (!hasLocalJob) {
289→                    msg = host + " is NIMBY locked.";
290→                }
291→            } else if (!dispatchSupport.isCueBookable(host)) {
292→                msg = "The cue has no pending jobs";
293→            }
294→
295→            boolean bookingOff =
296→                    env.getProperty("dispatcher.turn_off_booking", Boolean.class, false);
297→            /*
298→             * If a message was set, the host is not bookable. Log the message and move on.
299→             */
300→            if (msg != null) {
301→                logger.trace(msg);
302→            } else if (bookingOff) {
303→                logger.debug("Booking has been turned off on Cuebot's configuration");
304→            } else {
305→                // check again. The dangling local host assignment could be removed.
306→                hasLocalJob = bookingManager.hasLocalHostAssignment(host);
307→
308→                /*
309→                 * Check to see if a local job has been assigned.
310→                 */
311→                if (hasLocalJob) {
312→                    if (!bookingManager.hasResourceDeficit(host)) {
313→                        bookingQueue.execute(new DispatchBookHostLocal(host, localDispatcher));
314→                    }
315→                    return;
316→                }
317→
318→                /*
319→                 * Check if the host prefers a show. If it does , dispatch to that show first.
320→                 */
321→                if (hostManager.isPreferShow(host)) {
322→                    bookingQueue.execute(new DispatchBookHost(host,
323→                            hostManager.getPreferredShow(host), dispatcher, env));
324→                    return;
325→                }
326→
327→                bookingQueue.execute(new DispatchBookHost(host, dispatcher, env));
328→            }
329→        } finally {
330→            if (reportQueue.getQueue().size() > 0 || System.currentTimeMillis() - startTime > 100) {
331→                /*
332→                 * Write a log if the host report takes a long time to process.
333→                 */
334→                CueUtil.logDuration(startTime,
335→                        "host report " + report.getHost().getName() + " with "
336→                                + report.getFramesCount() + " running frames, waiting: "
337→                                + reportQueue.getQueue().size());
338→            }
339→        }
340→    }
