342→    /**
343→     * Check if a reported temp storage size and availability is enough for running a job
344→     *
345→     * Use dispatcher.min_available_temp_storage_percentage (opencue.properties) to define what's
346→     * the accepted threshold. Providing hostOs is necessary as this feature is currently not
347→     * available on Windows hosts
348→     *
349→     * @param tempTotalStorage Total storage on the temp directory
350→     * @param tempFreeStorage Free storage on the temp directory
351→     * @param hostOs Reported operational systems
352→     * @return
353→     */
354→    private boolean isTempDirStorageEnough(Long tempTotalStorage, Long tempFreeStorage,
355→            String[] hostOs) {
356→        // The minimum amount of free space in the temporary directory to book a host
357→        int minAvailableTempPercentage = env.getRequiredProperty(
358→                "dispatcher.min_available_temp_storage_percentage", Integer.class);
359→
360→        return (minAvailableTempPercentage == -1 ||
361→        // It is safe to assume multiple OSs imply windows is not the base OS,
362→        // threfore Windows will always report a single hostOs
363→                (hostOs.length == 1 && hostOs[0].equalsIgnoreCase(WINDOWS_OS))
364→                || (((tempFreeStorage * 100.0) / tempTotalStorage) >= minAvailableTempPercentage));
365→    }
366→
367→    /**
368→     * Update the hardware state property.
369→     *
370→     * If a host pings in with a different hardware state than what is currently in the DB, the
371→     * state is updated. If the hardware state is Rebooting or RebootWhenIdle, then state can only
372→     * be updated with a boot report. If the state is Repair, then state is never updated via RQD.
373→     *
374→     * @param host
375→     * @param reportState
376→     * @param isBoot
377→     */
378→    private void changeHardwareState(DispatchHost host, HardwareState reportState, boolean isBoot) {
379→        // If the states are the same there is no reason to do this update.
380→        if (host.hardwareState.equals(reportState)) {
381→            return;
382→        }
383→
384→        HardwareState previousState = host.hardwareState;
385→        boolean stateChanged = false;
386→
387→        switch (host.hardwareState) {
388→            case DOWN:
389→                hostManager.setHostState(host, HardwareState.UP);
390→                host.hardwareState = HardwareState.UP;
391→                stateChanged = true;
392→                break;
393→            case REBOOTING:
394→            case REBOOT_WHEN_IDLE:
395→                // Rebooting hosts only change to UP when processing a boot report
396→                if (isBoot) {
397→                    hostManager.setHostState(host, HardwareState.UP);
398→                    host.hardwareState = HardwareState.UP;
399→                    stateChanged = true;
400→                }
401→                break;
402→            case REPAIR:
403→                // Do not change the state of the host if its in a repair state.
404→                break;
405→            default:
406→                hostManager.setHostState(host, reportState);
407→                host.hardwareState = reportState;
408→                stateChanged = true;
409→                break;
410→        }
411→
412→        // Publish host state change event
413→        if (stateChanged) {
414→            publishHostEvent(host, previousState, null);
415→        }
416→    }
417→
418→    /**
419→     * Prevent cue frames from booking on hosts with full temporary directories.
420→     *
421→     * Change host state to REPAIR or UP according to the amount of free space in the temporary
422→     * directory: - Set the host state to REPAIR, when the amount of free space in the temporary
423→     * directory is less than the minimum required. - Set the host state to UP, when the amount of
424→     * free space in the temporary directory is greater or equal to the minimum required and the
425→     * host has a comment with subject: SUBJECT_COMMENT_FULL_TEMP_DIR
426→     *
427→     * @param host
428→     * @param reportHost
429→     * @return
430→     */
431→    private boolean changeStateForTempDirStorage(DispatchHost host, RenderHost reportHost) {
432→        // The minimum amount of free space in the temporary directory to book a host
433→        int minAvailableTempPercentage = env.getRequiredProperty(
434→                "dispatcher.min_available_temp_storage_percentage", Integer.class);
435→
436→        // Prevent cue frames from booking on hosts with full temporary directories
437→        boolean hasEnoughTempStorage = isTempDirStorageEnough(reportHost.getTotalMcp(),
438→                reportHost.getFreeMcp(), host.getOs());
439→        if (!hasEnoughTempStorage && host.hardwareState == HardwareState.UP) {
440→            // Insert a comment indicating that the Host status = Repair with reason = Full
441→            // temporary directory
442→            CommentDetail c = new CommentDetail();
443→            c.subject = SUBJECT_COMMENT_FULL_TEMP_DIR;
444→            c.user = CUEBOT_COMMENT_USER;
445→            c.timestamp = null;
446→            long requiredTempMb =
447→                    (long) (((minAvailableTempPercentage / 100.0) * reportHost.getTotalMcp())
448→                            / 1024);
449→            c.message = "Host " + host.getName()
450→                    + " marked as REPAIR. The current amount of free space in the "
451→                    + "temporary directory (mcp) is " + (reportHost.getFreeMcp() / 1024)
452→                    + "MB. It must have at least " + ((requiredTempMb))
453→                    + "MB of free space in temporary directory";
454→            commentManager.addComment(host, c);
455→
456→            // Set the host state to REPAIR
457→            hostManager.setHostState(host, HardwareState.REPAIR);
458→            host.hardwareState = HardwareState.REPAIR;
459→
460→            return true;
461→        } else if (hasEnoughTempStorage && host.hardwareState == HardwareState.REPAIR) {
462→            // Check if the host with REPAIR status has comments with
463→            // subject=SUBJECT_COMMENT_FULL_TEMP_DIR and
464→            // user=CUEBOT_COMMENT_USER and delete the comments, if they exist
465→            boolean commentsDeleted = commentManager.deleteCommentByHostUserAndSubject(host,
466→                    CUEBOT_COMMENT_USER, SUBJECT_COMMENT_FULL_TEMP_DIR);
467→
468→            if (commentsDeleted) {
469→                // Set the host state to UP
470→                hostManager.setHostState(host, HardwareState.UP);
471→                host.hardwareState = HardwareState.UP;
472→                return true;
473→            }
474→        }
475→        return false;
476→    }
