478→    /**
479→     * Changes the NIMBY lock state. If the DB indicates a NIMBY lock but RQD does not, then the
480→     * host is unlocked. If the DB indicates the host is not locked but RQD indicates it is, the
481→     * host is locked.
482→     *
483→     * @param host
484→     * @param rh
485→     */
486→    private void changeNimbyState(DispatchHost host, RenderHost rh) {
487→        if (rh.getNimbyLocked()) {
488→            if (host.lockState.equals(LockState.OPEN)) {
489→                host.lockState = LockState.NIMBY_LOCKED;
490→                hostManager.setHostLock(host, LockState.NIMBY_LOCKED, new Source("NIMBY"));
491→            }
492→        } else {
493→            if (host.lockState.equals(LockState.NIMBY_LOCKED)) {
494→                host.lockState = LockState.OPEN;
495→                hostManager.setHostLock(host, LockState.OPEN, new Source("NIMBY"));
496→            }
497→        }
498→    }
499→
500→    /**
501→     * Changes the Lock state of the host. Looks at the number of locked cores and sets host to
502→     * locked if all cores are locked.
503→     *
504→     * @param host DispatchHost
505→     * @param coreInfo CoreDetail
506→     */
507→    private void changeLockState(DispatchHost host, CoreDetail coreInfo) {
508→        if (host.lockState == LockState.LOCKED) {
509→            if (coreInfo.getLockedCores() < coreInfo.getTotalCores()) {
510→                host.lockState = LockState.OPEN;
511→                hostManager.setHostLock(host, LockState.OPEN, new Source("cores"));
512→            }
513→        } else if (coreInfo.getLockedCores() >= coreInfo.getTotalCores()) {
514→            host.lockState = LockState.LOCKED;
515→            hostManager.setHostLock(host, LockState.LOCKED, new Source("cores"));
516→        }
517→    }
