519→    /**
520→     * Prevent host from entering an OOM state where oom-killer might start killing important OS
521→     * processes and frames start using SWAP memory The kill logic will kick in one of the following
522→     * conditions is met: - Host has less than oom_max_safe_used_physical_memory_threshold memory
523→     * available and less than oom_max_safe_used_swap_memory_threshold swap available - A frame is
524→     * taking more than OOM_FRAME_OVERBOARD_PERCENT of what it had reserved For frames that are
525→     * using more than they had reserved but not above the threshold, negotiate expanding the
526→     * reservations with other frames on the same host
527→     *
528→     * @param dispatchHost
529→     * @param report
530→     */
531→    private void handleMemoryUsage(final DispatchHost dispatchHost, RenderHost renderHost,
532→            List<RunningFrameInfo> runningFrames) {
533→        // Don't keep memory balances on nimby hosts and hosts with invalid memory
534→        // information
535→        if (dispatchHost.isNimby || renderHost.getTotalMem() <= 0) {
536→            return;
537→        }
538→
539→        final double OOM_MAX_SAFE_USED_PHYSICAL_THRESHOLD = env.getRequiredProperty(
540→                "dispatcher.oom_max_safe_used_physical_memory_threshold", Double.class);
541→        final double OOM_MAX_SAFE_USED_SWAP_THRESHOLD = env.getRequiredProperty(
542→                "dispatcher.oom_max_safe_used_swap_memory_threshold", Double.class);
543→        final double OOM_FRAME_OVERBOARD_ALLOWED_THRESHOLD = env.getRequiredProperty(
544→                "dispatcher.oom_frame_overboard_allowed_threshold", Double.class);
545→
546→        Double physMemoryUsageRatio = renderHost.getTotalMem() > 0
547→                ? 1.0 - renderHost.getFreeMem() / (double) renderHost.getTotalMem()
548→                : 0.0;
549→
550→        Double swapMemoryUsageRatio = renderHost.getTotalSwap() > 0
551→                ? 1.0 - renderHost.getFreeSwap() / (double) renderHost.getTotalSwap()
552→                : 0.0;
553→
554→        // If checking for the swap threshold has been disabled, only memory usage is
555→        // taken into consideration.
556→        // If checking for memory has been disabled, checking for swap isolated is not
557→        // safe, therefore disabled
558→        boolean memoryWarning = false;
559→        if (OOM_MAX_SAFE_USED_PHYSICAL_THRESHOLD > 0.0 && OOM_MAX_SAFE_USED_SWAP_THRESHOLD > 0.0
560→                && !physMemoryUsageRatio.isNaN() && !swapMemoryUsageRatio.isNaN()) {
561→            memoryWarning = physMemoryUsageRatio > OOM_MAX_SAFE_USED_PHYSICAL_THRESHOLD
562→                    && swapMemoryUsageRatio > OOM_MAX_SAFE_USED_SWAP_THRESHOLD;
563→        } else if (OOM_MAX_SAFE_USED_PHYSICAL_THRESHOLD > 0.0 && !physMemoryUsageRatio.isNaN()) {
564→            memoryWarning = physMemoryUsageRatio > OOM_MAX_SAFE_USED_PHYSICAL_THRESHOLD;
565→        }
566→
567→        if (memoryWarning) {
568→            logger.warn("Memory warning(" + renderHost.getName() + "): physMemoryRatio: "
569→                    + physMemoryUsageRatio + ", swapRatio: " + swapMemoryUsageRatio);
570→            // Try to kill frames using swap memory as they are probably performing poorly
571→            long swapUsed = renderHost.getTotalSwap() - renderHost.getFreeSwap();
572→            long maxSwapUsageAllowed =
573→                    (long) (renderHost.getTotalSwap() * OOM_MAX_SAFE_USED_SWAP_THRESHOLD);
574→
575→            // Sort runningFrames bassed on how much swap they are using
576→            runningFrames.sort(
577→                    Comparator.comparingLong((RunningFrameInfo frame) -> frame.getUsedSwapMemory())
578→                            .reversed());
579→
580→            int killAttemptsRemaining = 5;
581→            for (RunningFrameInfo frame : runningFrames) {
582→                // Reached the first frame on the sorted list without swap usage
583→                if (frame.getUsedSwapMemory() <= 0) {
584→                    break;
585→                }
586→                if (killProcForMemory(frame.getFrameId(), renderHost.getName(),
587→                        KillCause.HostUnderOom)) {
588→                    swapUsed -= frame.getUsedSwapMemory();
589→                    logger.info("Memory warning(" + renderHost.getName() + "): "
590→                            + "Killing frame on " + frame.getJobName() + "." + frame.getFrameName()
591→                            + ", using too much swap.");
592→                }
593→
594→                killAttemptsRemaining -= 1;
595→                if (killAttemptsRemaining <= 0 || swapUsed <= maxSwapUsageAllowed) {
596→                    break;
597→                }
598→            }
599→        } else {
600→            // When no mass cleaning was required, check for frames going overboard
601→            // if frames didn't go overboard, manage its reservations trying to increase
602→            // them accordingly
603→            for (final RunningFrameInfo frame : runningFrames) {
604→                if (OOM_FRAME_OVERBOARD_ALLOWED_THRESHOLD > 0 && isFrameOverboard(frame)) {
605→                    if (!killFrameOverusingMemory(frame, dispatchHost.getName())) {
606→                        logger.warn("Frame " + frame.getJobName() + "." + frame.getFrameName()
607→                                + " is overboard but could not be killed");
608→                    }
609→                } else {
610→                    handleMemoryReservations(frame);
611→                }
612→            }
613→        }
614→    }
