617→        FrameOverboard("This frame is using more memory than it had reserved."), HostUnderOom(
618→                "Frame killed by host under OOM pressure"), FrameTimedOut(
619→                        "Frame timed out"), FrameLluTimedOut(
620→                                "Frame LLU timed out"), FrameVerificationFailure(
621→                                        "Frame failed to be verified on the database");
