635→    private boolean killFrameOverusingMemory(RunningFrameInfo frame, String hostname) {
636→        try {
637→            VirtualProc proc = hostManager.getVirtualProc(frame.getResourceId());
638→
639→            // Don't mess with localDispatch procs
640→            if (proc.isLocalDispatch) {
641→                return false;
642→            }
643→            boolean killed = killProcForMemory(proc.frameId, hostname, KillCause.FrameOverboard);
644→            if (killed) {
645→                logger.info("Killing frame on " + frame.getJobName() + "." + frame.getFrameName()
646→                        + ", using too much memory.");
647→            }
648→            return killed;
649→        } catch (EmptyResultDataAccessException e) {
650→            return false;
651→        }
652→    }
