654→    private boolean getKillClearance(String hostname, String frameId) {
655→        String cacheKey = hostname + "-" + frameId;
656→        final int FRAME_KILL_RETRY_LIMIT =
657→                env.getRequiredProperty("dispatcher.frame_kill_retry_limit", Integer.class);
658→
659→        // Cache frame+host receiving a killRequest and count how many times the request
660→        // is being retried
661→        // meaning rqd is probably failing at attempting to kill the related proc
662→        long cachedCount;
663→        try {
664→            cachedCount = 1 + killRequestCounterCache.get(cacheKey, () -> 0L);
665→        } catch (ExecutionException e) {
666→            return false;
667→        }
668→        killRequestCounterCache.put(cacheKey, cachedCount);
669→        if (cachedCount > FRAME_KILL_RETRY_LIMIT) {
670→            // If the kill retry limit has been reached, notify prometheus of the issue and
671→            // give up
672→            if (!dispatcher.isTestMode()) {
673→                try {
674→                    FrameInterface frame = jobManager.getFrame(frameId);
675→                    JobInterface job = jobManager.getJob(frame.getJobId());
676→                    prometheusMetrics.incrementFrameKillFailureCounter(hostname, job.getName(),
677→                            frame.getName(), frameId);
678→                } catch (EmptyResultDataAccessException e) {
679→                    logger.info("Trying to kill a frame that no longer exists: host=" + hostname
680→                            + " frameId=" + frameId);
681→                }
682→            }
683→            return false;
684→        }
685→        return true;
686→    }
687→
688→    private boolean killProcForMemory(String frameId, String hostname, KillCause killCause) {
689→        if (!getKillClearance(hostname, frameId)) {
690→            return false;
691→        }
692→
693→        FrameInterface frame = jobManager.getFrame(frameId);
694→        if (dispatcher.isTestMode()) {
695→            // Different threads don't share the same database state on the test environment
696→            (new DispatchRqdKillFrameMemory(hostname, frame, killCause.toString(), rqdClient,
697→                    dispatchSupport, dispatcher.isTestMode())).run();
698→        } else {
699→            try {
700→                killQueue.execute(new DispatchRqdKillFrameMemory(hostname, frame,
701→                        killCause.toString(), rqdClient, dispatchSupport, dispatcher.isTestMode()));
702→                prometheusMetrics.incrementFrameKilledCounter(hostname, killCause);
703→            } catch (TaskRejectedException e) {
704→                logger.warn("Unable to add a DispatchRqdKillFrame request, task rejected, " + e);
705→                return false;
706→            }
707→        }
708→        DispatchSupport.killedOffenderProcs.incrementAndGet();
709→        return true;
710→    }
711→
712→    private boolean killFrame(String frameId, String hostname, KillCause killCause) {
713→        if (!getKillClearance(hostname, frameId)) {
714→            return false;
715→        }
716→
717→        if (dispatcher.isTestMode()) {
718→            // Different threads don't share the same database state on the test environment
719→            (new DispatchRqdKillFrame(hostname, frameId, killCause.toString(), rqdClient)).run();
720→        } else {
721→            try {
722→                killQueue.execute(new DispatchRqdKillFrame(hostname, frameId, killCause.toString(),
723→                        rqdClient));
724→                prometheusMetrics.incrementFrameKilledCounter(hostname, killCause);
725→            } catch (TaskRejectedException e) {
726→                logger.warn("Unable to add a DispatchRqdKillFrame request, task rejected, " + e);
727→            }
728→        }
729→        DispatchSupport.killedOffenderProcs.incrementAndGet();
730→        return true;
731→    }
