733→    /**
734→     * Check frame memory usage comparing the amount used with the amount it had reserved
735→     *
736→     * @param frame
737→     * @return
738→     */
739→    private boolean isFrameOverboard(final RunningFrameInfo frame) {
740→        final double OOM_FRAME_OVERBOARD_ALLOWED_THRESHOLD = env.getRequiredProperty(
741→                "dispatcher.oom_frame_overboard_allowed_threshold", Double.class);
742→
743→        if (OOM_FRAME_OVERBOARD_ALLOWED_THRESHOLD < 0) {
744→            return false;
745→        }
746→
747→        double rss = (double) frame.getRss();
748→        double maxRss = (double) frame.getMaxRss();
749→        final double MAX_RSS_OVERBOARD_THRESHOLD = OOM_FRAME_OVERBOARD_ALLOWED_THRESHOLD * 2;
750→        final double RSS_AVAILABLE_FOR_MAX_RSS_TRIGGER = 0.1;
751→
752→        try {
753→            VirtualProc proc = hostManager.getVirtualProc(frame.getResourceId());
754→            double reserved = (double) proc.memoryReserved;
755→
756→            // Last memory report is higher than the threshold
757→            if (isOverboard(rss, reserved, OOM_FRAME_OVERBOARD_ALLOWED_THRESHOLD)) {
758→                return true;
759→            }
760→            // If rss is not overboard, handle the situation where the frame might be going
761→            // overboard from
762→            // time to time but the last report wasn't during a spike. For this case,
763→            // consider a combination
764→            // of rss and maxRss. maxRss > 2 * threshold and rss > 0.9
765→            else {
766→                return (isOverboard(maxRss, reserved, MAX_RSS_OVERBOARD_THRESHOLD)
767→                        && isOverboard(rss, reserved, -RSS_AVAILABLE_FOR_MAX_RSS_TRIGGER));
768→            }
769→        } catch (EmptyResultDataAccessException e) {
770→            logger.info("HostReportHandler(isFrameOverboard): Virtual proc for frame "
771→                    + frame.getFrameName() + " on job " + frame.getJobName()
772→                    + " doesn't exist on the database");
773→            // Not able to mark the frame overboard is it couldn't be found on the db.
774→            // Proc accounting (verifyRunningProc) should take care of it
775→            return false;
776→        }
777→    }
778→
779→    private boolean isOverboard(double value, double total, double threshold) {
780→        return value / total >= (1 + threshold);
781→    }
