783→    /**
784→     * Handle memory reservations for the given frame
785→     *
786→     * @param frame
787→     */
788→    private void handleMemoryReservations(final RunningFrameInfo frame) {
789→        VirtualProc proc = null;
790→        try {
791→            proc = hostManager.getVirtualProc(frame.getResourceId());
792→
793→            if (proc.isLocalDispatch) {
794→                return;
795→            }
796→
797→            if (dispatchSupport.increaseReservedMemory(proc, frame.getRss())) {
798→                proc.memoryReserved = frame.getRss();
799→                logger.info("frame " + frame.getFrameName() + " on job " + frame.getJobName()
800→                        + " increased its reserved memory to " + CueUtil.KbToMb(frame.getRss()));
801→            }
802→        } catch (ResourceReservationFailureException e) {
803→            if (proc != null) {
804→                long memNeeded = frame.getRss() - proc.memoryReserved;
805→                logger.info("frame " + frame.getFrameName() + " on job " + frame.getJobName()
806→                        + "was unable to reserve an additional " + CueUtil.KbToMb(memNeeded)
807→                        + "on proc " + proc.getName() + ", " + e);
808→                try {
809→                    if (dispatchSupport.balanceReservedMemory(proc, memNeeded)) {
810→                        proc.memoryReserved = frame.getRss();
811→                        logger.info("was able to balance host: " + proc.getName());
812→                    } else {
813→                        logger.info("failed to balance host: " + proc.getName());
814→                    }
815→                } catch (Exception ex) {
816→                    logger.warn("failed to balance host: " + proc.getName() + ", " + e);
817→                }
818→            } else {
819→                logger.info("frame " + frame.getFrameName() + " on job " + frame.getJobName()
820→                        + "was unable to reserve an additional memory. Proc could not be found");
821→            }
822→        } catch (EmptyResultDataAccessException e) {
823→            logger.info("HostReportHandler: Memory reservations for frame " + frame.getFrameName()
824→                    + " on job " + frame.getJobName() + " proc could not be found");
825→        }
826→    }
