828→    /**
829→     * Kill frames that over run.
830→     *
831→     * @param rFrames
832→     */
833→    private void killTimedOutFrames(List<RunningFrameInfo> runningFrames, String hostname) {
834→        for (RunningFrameInfo frame : runningFrames) {
835→            String layerId = frame.getLayerId();
836→
837→            try {
838→                LayerDetail layer = layerDao.getLayerDetail(layerId);
839→                long runtimeMinutes =
840→                        ((System.currentTimeMillis() - frame.getStartTime()) / 1000l) / 60;
841→
842→                if (layer.timeout != 0 && runtimeMinutes > layer.timeout) {
843→                    killFrame(frame.getFrameId(), hostname, KillCause.FrameTimedOut);
844→                } else if (layer.timeout_llu != 0 && frame.getLluTime() != 0) {
845→                    long r = System.currentTimeMillis() / 1000;
846→                    long lastUpdate = (r - frame.getLluTime()) / 60;
847→
848→                    if (layer.timeout_llu != 0 && lastUpdate > (layer.timeout_llu - 1)) {
849→                        killFrame(frame.getFrameId(), hostname, KillCause.FrameLluTimedOut);
850→                    }

 850→                    }
 851→                }
 852→            } catch (EmptyResultDataAccessException e) {
 853→                logger.info("Unable to get layer with id=" + layerId);
 854→            }
 855→        }
 856→    }
