 860→     *
 861→     * @param rFrames
 862→     */
 863→    private void updateMemoryUsageAndLluTime(List<RunningFrameInfo> rFrames) {
 864→        for (RunningFrameInfo rf : rFrames) {
 865→            FrameInterface frame = jobManager.getFrame(rf.getFrameId());
 866→
 867→            dispatchSupport.updateFrameMemoryUsageAndLluTime(frame, rf.getRss(), rf.getMaxRss(),
 868→                    rf.getPss(), rf.getMaxPss(), rf.getLluTime());
 869→
 870→            dispatchSupport.updateProcMemoryUsage(frame, rf.getRss(), rf.getMaxRss(), rf.getPss(),
 871→                    rf.getMaxPss(), rf.getVsize(), rf.getMaxVsize(), rf.getUsedGpuMemory(),
 872→                    rf.getMaxUsedGpuMemory(), rf.getUsedSwapMemory(),
 873→                    rf.getChildren().toByteArray());
 874→        }
 875→
 876→        updateJobMemoryUsage(rFrames);
 877→        updateLayerMemoryUsage(rFrames);
 878→    }
