 880→    /**
 881→     * Update job memory using for the given list of frames.
 882→     *
 883→     * @param frames
 884→     */
 885→    private void updateJobMemoryUsage(List<RunningFrameInfo> frames) {
 886→        final Map<JobEntity, Long> jobs = new HashMap<JobEntity, Long>(frames.size());
 887→        final Map<JobEntity, Long> jobsPss = new HashMap<JobEntity, Long>(frames.size());
 888→
 889→        for (RunningFrameInfo frame : frames) {
 890→            JobEntity job = new JobEntity(frame.getJobId());
 891→            if (jobs.containsKey(job)) {
 892→                if (jobs.get(job) < frame.getMaxRss()) {
 893→                    jobs.put(job, frame.getMaxRss());
 894→                }
 895→            } else {
 896→                jobs.put(job, frame.getMaxRss());
 897→            }
 898→
 899→            if (jobsPss.containsKey(job)) {
 900→                if (jobsPss.get(job) < frame.getMaxPss()) {
 901→                    jobsPss.put(job, frame.getMaxPss());
 902→                }
 903→            } else {
 904→                jobsPss.put(job, frame.getMaxPss());
 905→            }
 906→        }
 907→
 908→        for (Map.Entry<JobEntity, Long> set : jobs.entrySet()) {
 909→            jobDao.updateMaxRSS(set.getKey(), set.getValue());
 910→        }
 911→
 912→        for (Map.Entry<JobEntity, Long> set : jobsPss.entrySet()) {
 913→            jobDao.updateMaxPSS(set.getKey(), set.getValue());
 914→        }
 915→    }
