 917→    /**
 918→     * Update layer memory usage for the given list of frames.
 919→     *
 920→     * @param frames
 921→     */
 922→    private void updateLayerMemoryUsage(List<RunningFrameInfo> frames) {
 923→        final Map<LayerEntity, Long> layers = new HashMap<LayerEntity, Long>(frames.size());
 924→        final Map<LayerEntity, Long> layersPss = new HashMap<LayerEntity, Long>(frames.size());
 925→
 926→        for (RunningFrameInfo frame : frames) {
 927→            LayerEntity layer = new LayerEntity(frame.getLayerId());
 928→            if (layers.containsKey(layer)) {
 929→                if (layers.get(layer) < frame.getMaxRss()) {
 930→                    layers.put(layer, frame.getMaxRss());
 931→                }
 932→            } else {
 933→                layers.put(layer, frame.getMaxRss());
 934→            }
 935→
 936→            if (layersPss.containsKey(layer)) {
 937→                if (layersPss.get(layer) < frame.getMaxPss()) {
 938→                    layersPss.put(layer, frame.getMaxPss());
 939→                }
 940→            } else {
 941→                layersPss.put(layer, frame.getMaxPss());
 942→            }
 943→        }
 944→
 945→        /* Attempt to update the max RSS value for the job **/
 946→        for (Map.Entry<LayerEntity, Long> set : layers.entrySet()) {
 947→            layerDao.increaseLayerMinMemory(set.getKey(), set.getValue());
 948→            layerDao.updateLayerMaxRSS(set.getKey(), set.getValue(), false);
 949→        }
 950→
 951→        /* Attempt to update the max PSS value for the layer **/
 952→        for (Map.Entry<LayerEntity, Long> set : layersPss.entrySet()) {
 953→            layerDao.updateLayerMaxPSS(set.getKey(), set.getValue(), false);
 954→        }
 955→    }
