 957→    /**
 958→     * Number of seconds before running frames have to exist before being verified against the DB.
 959→     */
 960→    private static final long FRAME_VERIFICATION_GRACE_PERIOD_SECONDS = 120;
 961→
 962→    /**
 963→     * Verify all running frames in the given report against the DB. Frames that have not been
 964→     * running for at least FRAME_VERIFICATION_GRACE_PERIOD_SECONDS are skipped.
 965→     *
 966→     * If a frame->proc mapping is not verified then the record for the proc is pulled from the DB.
 967→     * If the proc doesn't exist at all, then the frame is killed with the message: "but the DB did
 968→     * not reflect this"
 969→     *
 970→     * The main reason why a proc no longer exists is that the cue though the host went down and
 971→     * cleared out all running frames.
 972→     *
 973→     * @param report
 974→     */
 975→    public List<RunningFrameInfo> verifyRunningFrameInfo(HostReport report) {
 976→        List<RunningFrameInfo> runningFrames =
 977→                new ArrayList<RunningFrameInfo>(report.getFramesCount());
 978→
 979→        for (RunningFrameInfo runningFrame : report.getFramesList()) {
 980→            long runtimeSeconds =
 981→                    (System.currentTimeMillis() - runningFrame.getStartTime()) / 1000l;
 982→
 983→            // Don't test frames that haven't been running long enough.
 984→            if (runtimeSeconds < FRAME_VERIFICATION_GRACE_PERIOD_SECONDS) {
 985→                logger.info("verified " + runningFrame.getJobName() + "/"
 986→                        + runningFrame.getFrameName() + " on " + report.getHost().getName()
 987→                        + " by grace period " + runtimeSeconds + " seconds.");
 988→                runningFrames.add(runningFrame);
 989→                continue;
 990→            }
 991→
 992→            if (hostManager.verifyRunningProc(runningFrame.getResourceId(),
 993→                    runningFrame.getFrameId())) {
 994→                runningFrames.add(runningFrame);
 995→                continue;
 996→            }
 997→
 998→            /*
 999→             * The frame this proc is running is no longer assigned to this proc. Don't ever touch
1000→             * the frame record. If we make it here that means the proc has been running for over 2
1001→             * min.
1002→             */
1003→            String msg;
1004→            VirtualProc proc = null;
1005→
1006→            try {
1007→                proc = hostManager.getVirtualProc(runningFrame.getResourceId());
1008→                msg = "Virtual proc " + proc.getProcId() + "is assigned to " + proc.getFrameId()
1009→                        + " not " + runningFrame.getFrameId();
1010→            } catch (Exception e) {
1011→                /*
1012→                 * This will happen if the host goes offline and then comes back. In this case, we
1013→                 * don't touch the frame since it might already be running somewhere else. We do
1014→                 * however kill the proc.
1015→                 */
1016→                msg = "Virtual proc did not exist.";
1017→            }
1018→
1019→            DispatchSupport.accountingErrors.incrementAndGet();
1020→            if (proc != null && hostManager.isOprhan(proc)) {
1021→                dispatchSupport.clearVirtualProcAssignement(proc);
1022→                dispatchSupport.unbookProc(proc);
1023→                proc = null;
1024→            }
1025→            if (proc == null) {
1026→                // A frameCompleteReport might have been delivered before this report was
1027→                // processed
1028→                FrameDetail frameLatestVersion =
1029→                        jobManager.getFrameDetail(runningFrame.getFrameId());
1030→                if (frameLatestVersion.state != FrameState.RUNNING) {
1031→                    logger.info("DelayedVerification, the proc " + runningFrame.getResourceId()
1032→                            + " on host " + report.getHost().getName() + " has already Completed "
1033→                            + runningFrame.getJobName() + "/" + runningFrame.getFrameName());
1034→                } else if (killFrame(runningFrame.getFrameId(), report.getHost().getName(),
1035→                        KillCause.FrameVerificationFailure)) {
1036→                    logger.info("FrameVerificationError, the proc " + runningFrame.getResourceId()
1037→                            + " on host " + report.getHost().getName() + " was running for "
1038→                            + (runtimeSeconds / 60.0f) + " minutes " + runningFrame.getJobName()
1039→                            + "/" + runningFrame.getFrameName() + " but the DB did not "
1040→                            + "reflect this. " + msg);
1041→                } else {
1042→                    logger.warn("FrameStuckWarning: frameId=" + runningFrame.getFrameId()
1043→                            + " render_node=" + report.getHost().getName() + " - "
1044→                            + runningFrame.getJobName() + "/" + runningFrame.getFrameName());
1045→                }
1046→            }
1047→        }
1048→        return runningFrames;
1049→    }

