 86→    public boolean shutdownJob(JobInterface job, Source source, boolean isManualKill) {
 87→
 88→        if (isManualKill && source.getReason().isEmpty()) {
 89→            logger.info(job.getName() + "/" + job.getId() + " **Invalid Job Kill Request** for "
 90→                    + source.toString());
 91→        } else {
 92→            if (jobManager.shutdownJob(job)) {
 93→                /*
 94→                 * Satisfy any dependencies on just the job record, not layers or frames.
 95→                 */
 96→                satisfyWhatDependsOn(job);
 97→
 98→                if (departmentManager.isManaged(job)) {
 99→                    departmentManager.syncJobsWithTask(job);
100→                }
101→
102→                if (isManualKill) {
103→                    logger.info(job.getName() + "/" + job.getId() + " is being manually killed by "
104→                            + source.toString());
105→
106→                    /**
107→                     * Sleep a bit here in case any frames were dispatched during the job shutdown
108→                     * process.
109→                     */
110→                    try {
111→                        Thread.sleep(3000);
112→                    } catch (InterruptedException e1) {
113→                        logger.info(job.getName() + "/" + job.getId()
114→                                + " shutdown thread was interrupted.");
115→                        Thread.currentThread().interrupt();
116→                    }
117→
118→                    // Report kill requests to sentry
119→                    Sentry.configureScope(scope -> {
120→                        scope.setExtra("Job Name", job.getName());
121→                        scope.setExtra("Job ID", job.getId());
122→                        scope.setExtra("Job Details", source.toString());
123→                        scope.setExtra("Kill Reason", source.getReason());
124→                        scope.setTag("job", job.getName());
125→                        Sentry.captureMessage("Kill Request Successful");
126→                    });
127→
128→                    FrameSearchInterface search = frameSearchFactory.create(job);
129→                    FrameSearchCriteria newCriteria = search.getCriteria();
130→                    FrameStateSeq states = newCriteria.getStates().toBuilder()
131→                            .addFrameStates(FrameState.RUNNING).build();
132→                    search.setCriteria(newCriteria.toBuilder().setStates(states).build());
133→
134→                    for (FrameInterface frame : jobManager.findFrames(search)) {
135→
136→                        VirtualProc proc = null;
137→                        try {
138→                            proc = hostManager.findVirtualProc(frame);
139→                        } catch (DataAccessException e) {
140→                            logger.warn("Unable to find proc to kill frame " + frame
141→                                    + " on job shutdown operation, " + e);
142→                        }
143→
144→                        if (manualStopFrame(frame, FrameState.WAITING)) {
145→                            try {
146→                                if (proc != null) {
147→                                    kill(proc, source);
148→                                }
149→                            } catch (DataAccessException e) {
150→                                logger.warn("Failed to kill frame " + frame
151→                                        + " on job shutdown operation, " + e);
152→                            } catch (Exception e) {
153→                                logger.warn("error killing frame: " + frame);
154→                            }
155→                        }
156→                    }
157→                }
158→
159→                /*
160→                 * Send mail after all frames have been stopped or else the email will have
161→                 * inaccurate numbers.
162→                 */
163→                emailSupport.sendShutdownEmail(job);
164→
165→                // Record job completion metric
166→                if (prometheusMetrics != null && showDao != null) {
167→                    JobDetail jobDetail = jobManager.getJobDetail(job.getId());
168→                    String showName = showDao.getShowDetail(job.getShowId()).getName();
169→                    String state = isManualKill ? "KILLED" : "FINISHED";
170→                    prometheusMetrics.recordJobCompleted(state, showName, jobDetail.shot);
171→
172→                    // Record job core seconds histogram
173→                    ExecutionSummary execSummary = jobManager.getExecutionSummary(job);
174→                    prometheusMetrics.recordJobCoreSeconds(execSummary.coreTime, showName,
175→                            jobDetail.shot);
176→                }
177→
178→                // Publish job completed/killed event to Kafka
179→                if (kafkaEventPublisher != null && kafkaEventPublisher.isEnabled()) {
180→                    try {
181→                        JobDetail jobDetail = jobManager.getJobDetail(job.getId());
182→                        EventType eventType =
183→                                isManualKill ? EventType.JOB_KILLED : EventType.JOB_FINISHED;
184→                        JobState previousState = JobState.PENDING;
185→                        JobEvent jobEvent = monitoringEventBuilder.buildJobEvent(eventType,
186→                                jobDetail, previousState, null, null);
187→                        kafkaEventPublisher.publishJobEvent(jobEvent);
188→                    } catch (Exception e) {
189→                        logger.warn("Failed to publish job event", e);
190→                    }
191→                }
192→
193→                return true;
194→            }
195→        }
196→
197→        return false;
198→    }
