267→    /*
268→     * Destructive functions require a extra Source argument which contains information about the
269→     * user making the call. This information is propagated down to the frame log file.
270→     *
271→     * There are three main destructive functions. kill, retry, and eat.
272→     *
273→     * Before a frame is retried or eaten, the new frame state must be set and committed to the DB
274→     * before the call to RQD is made to actually kill the frame. This will tell the dispatcher what
275→     * to do with the frame when RQD sends in the FrameCompleteReport.
276→     *
277→     * See RqdReportManagerService.determineFrameState
278→     */
279→
280→    /**
281→     * Kill the specified frame. If RQD throws back an exception, the proc is considered lost and is
282→     * manually removed.
283→     *
284→     * @param p
285→     * @param source
286→     */
287→    public void kill(VirtualProc p, Source source) {
288→        try {
289→            rqdClient.killFrame(p, source.toString());
290→        } catch (java.lang.Throwable e) {
291→            dispatchSupport.lostProc(p, "clearing due to failed kill," + p.getName() + "," + e,
292→                    Dispatcher.EXIT_STATUS_FAILED_KILL);
293→        }
294→    }
295→
296→    /**
297→     * Kill a list procs. If RQD throws back an exception, the proc is considered lost and is
298→     * manually removed.
299→     *
300→     * @param procs
301→     * @param source
302→     */
303→    public void kill(Collection<VirtualProc> procs, Source source) {
304→        for (VirtualProc p : procs) {
305→            try {
306→                rqdClient.killFrame(p, source.toString());
307→            } catch (java.lang.Throwable e) {
308→                dispatchSupport.lostProc(p, "clearing due to failed kill," + p.getName() + "," + e,
309→                        Dispatcher.EXIT_STATUS_FAILED_KILL);
310→            }
311→        }
312→    }
