434→    /**
435→     * Retry a single frame.
436→     *
437→     * @param frame
438→     * @param source
439→     */
440→    public void retryFrame(FrameInterface frame, Source source) {
441→        /**
442→         * Have to find the proc before we stop the frame.
443→         */
444→        VirtualProc proc = null;
445→        try {
446→            proc = hostManager.findVirtualProc(frame);
447→        } catch (EmptyResultDataAccessException e) {
448→            logger.info("failed to obtain information for " + "proc running on frame: " + frame);
449→        }
450→
451→        if (manualStopFrame(frame, FrameState.WAITING)) {
452→            if (proc != null) {
453→                redirectManager.addRedirect(proc, (JobInterface) proc, false, source);
454→                kill(proc, source);
455→            }
456→        } else {
457→            jobManager.updateFrameState(frame, FrameState.WAITING);
458→        }
459→
460→        /**
461→         * If a frame is retried that was part of a dependency, that dependency should become active
462→         * again.
463→         */
464→
465→        // Handle FrameOnFrame depends.
466→        for (LightweightDependency depend : dependManager.getWhatDependsOn(frame, false)) {
467→            dependManager.unsatisfyDepend(depend);
468→        }
469→
470→        // Handle LayerOnLayer depends.
471→        for (LightweightDependency depend : dependManager.getWhatDependsOn((LayerInterface) frame,
472→                false)) {
473→            dependManager.unsatisfyDepend(depend);
474→        }
475→
476→        // set the job back to pending.
477→        jobManager.updateJobState(jobManager.getJob(frame.getJobId()), JobState.PENDING);
478→
479→    }
