494→    /**
495→     * Eat the specified frame. Eaten frames are considered "Succeeded" by the dispatcher. A Job
496→     * with all eaten frames will leave the cue.
497→     *
498→     * @param frame
499→     * @param source
500→     */
501→    public void eatFrame(FrameInterface frame, Source source) {
502→        /**
503→         * Have to find the proc before we stop the frame.
504→         */
505→        VirtualProc proc = null;
506→        try {
507→            proc = hostManager.findVirtualProc(frame);
508→        } catch (EmptyResultDataAccessException e) {
509→            logger.info("failed to obtain information " + "for proc running on frame: " + frame);
510→        }
511→
512→        if (manualStopFrame(frame, FrameState.EATEN)) {
513→            if (proc != null) {
514→                kill(proc, source);
515→            }
516→        } else {
517→            jobManager.updateFrameState(frame, FrameState.EATEN);
518→        }
519→        if (jobManager.isJobComplete(frame)) {
520→            queueShutdownJob(frame, source, false);
521→        }
522→    }
