537→    /**
538→     * Stops the specified frame. Return true if the call to this method actually stops the frame,
539→     * ie the state changes from Running to the given state. Return false if the frame was already
540→     * stopped.
541→     *
542→     * Stopping the frame also removes the link between the frame and the proc. The proc still
543→     * exists, but, its assigned frame is null.
544→     *
545→     * @param frame
546→     * @param state
547→     */
548→    private boolean manualStopFrame(FrameInterface frame, FrameState state) {
549→        if (dispatchSupport.stopFrame(frame, state, state.ordinal() + 500)) {
550→            dispatchSupport.updateUsageCounters(frame, state.ordinal() + 500);
551→            logger.info("Manually stopping frame: " + frame);
552→            return true;
553→        }
554→        return false;
555→    }
