168→    @Transactional(propagation = Propagation.REQUIRED)
169→    public void launchJobSpec(JobSpec spec) {
170→
171→        for (BuildableJob job : spec.getJobs()) {
172→
173→            JobDetail d = createJob(job);
174→            if (job.maxCoresOverride != null) {
175→                jobDao.updateMaxCores(d,
176→                        Convert.coresToWholeCoreUnits(job.maxCoresOverride.intValue()));
177→            }
178→            if (job.maxGpusOverride != null) {
179→                jobDao.updateMaxGpus(d, job.maxGpusOverride.intValue());
180→            }
181→            if (job.getPostJob() != null) {
182→                BuildableJob postJob = job.getPostJob();
183→                postJob.env.put("CUE_PARENT_JOB_ID", d.id);
184→                postJob.env.put("CUE_PARENT_JOB", d.name);
185→                createJob(postJob);
186→                jobDao.mapPostJob(job);
187→            }
188→        }
189→
190→        for (BuildableDependency dep : spec.getDepends()) {
191→            dep.setLaunchDepend(true);
192→            dependManager.createDepend(dep);
193→        }
194→
195→        for (BuildableJob job : spec.getJobs()) {
196→            jobDao.activateJob(job.detail, JobState.PENDING);
197→            if (job.getPostJob() != null) {
198→                jobDao.activateJob(job.getPostJob().detail, JobState.POSTED);
199→            }
200→        }
201→    }
202→
203→    @Transactional(propagation = Propagation.REQUIRED)
204→    public JobDetail createJob(BuildableJob buildableJob) {
205→
206→        logger.info("creating new job: " + buildableJob.detail.name);
207→        long startTime = System.currentTimeMillis();
208→
209→        if (jobDao.exists(buildableJob.detail.name)) {
210→            throw new JobLaunchException(
211→                    "error launching job, active job already exists: " + buildableJob.detail.name);
212→        }
213→
214→        if (buildableJob.getBuildableLayers().size() < 1) {
215→            throw new JobLaunchException("error launching job, there were no layers defined!");
216→        }
217→
218→        JobDetail job = buildableJob.detail;
219→
220→        try {
221→            /*
222→             * Get the last job with the same name and try to use the memory settings for that job.
223→             * Do this before inserting the new job we'll find this job as the last job.
224→             */
225→            JobDetail lastJob = null;
226→            try {
227→                lastJob = findLastJob(job.name);
228→                logger.info("Last job " + job.name + " was found as " + lastJob.name);
229→            } catch (Exception e) {
230→                logger.info("Last job " + job.name + " was NOT found");
231→                // don't have another version of the job in the DB.
232→            }
233→
234→            ShowEntity show = showDao.findShowDetail(job.showName);
235→            if (!job.isPaused) {
236→                job.isPaused = show.paused;
237→            }
238→
239→            job.showId = show.id;
240→            job.logDir = job.name;
241→
242→            /*
243→             * The job gets inserted into the root group and unknown department.
244→             */
245→            GroupDetail rootGroup = groupDao.getRootGroupDetail(job);
246→            job.groupId = rootGroup.id;
247→            job.deptId = rootGroup.deptId;
248→
249→            resolveFacility(job);
250→
251→            jobDao.insertJob(job, jobLogUtil);
252→            jobDao.insertEnvironment(job, buildableJob.env);
253→
254→            for (BuildableLayer buildableLayer : buildableJob.getBuildableLayers()) {
255→
256→                LayerDetail layer = buildableLayer.layerDetail;
257→                layer.jobId = job.id;
258→                layer.showId = show.id;
259→
260→                /** Not accurate anymore */
261→                List<Integer> frames = CueUtil.normalizeFrameRange(layer.range, layer.chunkSize);
262→                layer.totalFrameCount = frames.size();
263→
264→                if (lastJob != null && !buildableLayer.isMemoryOverride) {
265→                    long pastMaxRSS = layerDao.findPastMaxRSS(lastJob, layer.name);
266→                    if (pastMaxRSS > 0) {
267→                        logger.info("found new maxRSS for layer: " + layer.name + " " + pastMaxRSS);
268→                        layer.minimumMemory = pastMaxRSS;
269→                    }
270→                }
271→
272→                if (layer.minimumCores > 0
273→                        && layer.minimumCores < Dispatcher.CORE_POINTS_RESERVED_MIN) {
274→                    layer.minimumCores = Dispatcher.CORE_POINTS_RESERVED_MIN;
275→                }
276→
277→                logger.info("creating layer " + layer.name + " range: " + layer.range);
278→                layerDao.insertLayerDetail(layer);
279→                layerDao.insertLayerEnvironment(layer, buildableLayer.env);
280→                layer.limits.stream()
281→                        .forEach(ln -> addLayerLimit(layer, limitDao.findLimit(ln).getLimitId()));
282→                layer.outputs.stream().forEach(ln -> registerLayerOutput(layer, ln));
283→                frameDao.insertFrames(layer, frames);
284→            }
285→
286→            // The priority of a job is set on it's resource entry.
287→            // To update it we set the priority after it's been inserted.
288→            jobDao.updatePriority(job, job.priority);
289→
290→            /*
291→             * Finally, run any filters on the job which may set the job's priority.
292→             */
293→            filterManager.runFiltersOnJob(job);
294→
295→            CueUtil.logDuration(startTime, "created job " + job.getName() + " " + job.getId());
296→            return job;
297→
298→        } catch (Exception e) {
299→            logger.info("error launching job: " + job.name + "," + e);
300→            throw new JobLaunchException("error launching job: " + job.name + "," + e, e);

300→            throw new JobLaunchException("error launching job: " + job.name + "," + e, e);
301→        }
302→    }
