304→    private void resolveFacility(JobDetail job) {
305→        try {
306→            if (job.facilityName == null) {
307→                job.facilityId = facilityDao.getDefaultFacility().getId();
308→            } else {
309→                job.facilityId = facilityDao.getFacility(job.facilityName).getId();
310→            }
311→        } catch (Exception e) {
312→            throw new EntityRetrievalException("failed to find facility: " + job.facilityName, e);
313→        }
314→    }
