 19→/**
 20→ * A ThreadPoolExecutor with two additional features: - Handles repeated tasks by always keeping the
 21→ * latest version - With isHealthyOrShutdown, the threadpool will drain and clear resources when
 22→ * unhealthy
 23→ *
 24→ */
 25→public class HealthyThreadPool extends ThreadPoolExecutor {
 26→    // The service need s to be unhealthy for this period of time to report
 27→    private static final Logger logger = LogManager.getLogger("HEALTH");
 28→    // Threshold to consider healthy or unhealthy
 29→    private final int healthThreshold;
 30→    private final int poolSize;
 31→    private final int minUnhealthyPeriodMin;
 32→    private final QueueRejectCounter rejectCounter = new QueueRejectCounter();
 33→    private final Cache<String, KeyRunnable> taskCache;
 34→    private final String name;
 35→    private Date lastCheck = new Date();
 36→    private boolean wasHealthy = true;
 37→    protected final AtomicBoolean isShutdown = new AtomicBoolean(false);
 38→    private final int baseSleepTimeMillis;
 39→
 40→    /**
 41→     * Start a thread pool
 42→     *
 43→     * @param name For logging purposes
 44→     * @param healthThreshold Percentage that should be available to consider healthy
 45→     * @param minUnhealthyPeriodMin Period in min to consider a queue unhealthy
 46→     * @param poolSize how many jobs can be queued
 47→     * @param threadsMinimum Minimum number of threads
 48→     * @param threadsMaximum Maximum number of threads to grow to
 49→     */
 50→    public HealthyThreadPool(String name, int healthThreshold, int minUnhealthyPeriodMin,
 51→            int poolSize, int threadsMinimum, int threadsMaximum) {
 52→        this(name, healthThreshold, minUnhealthyPeriodMin, poolSize, threadsMinimum, threadsMaximum,
 53→                0);
 54→    }
 55→
 56→    /**
 57→     * Start a thread pool
 58→     *
 59→     * @param name For logging purposes
 60→     * @param healthThreshold Percentage that should be available to consider healthy
 61→     * @param minUnhealthyPeriodMin Period in min to consider a queue unhealthy
 62→     * @param poolSize how many jobs can be queued
 63→     * @param threadsMinimum Minimum number of threads
 64→     * @param threadsMaximum Maximum number of threads to grow to
 65→     * @param baseSleepTimeMillis Time a thread should sleep when the service is not under pressure
 66→     */
 67→    public HealthyThreadPool(String name, int healthThreshold, int minUnhealthyPeriodMin,
 68→            int poolSize, int threadsMinimum, int threadsMaximum, int baseSleepTimeMillis) {
 69→        super(threadsMinimum, threadsMaximum, 10, TimeUnit.SECONDS,
 70→                new LinkedBlockingQueue<Runnable>(poolSize));
 71→
 72→        logger.debug(name + ": Starting a new HealthyThreadPool");
 73→        this.name = name;
 74→        this.healthThreshold = healthThreshold;
 75→        this.poolSize = poolSize;
 76→        this.minUnhealthyPeriodMin = minUnhealthyPeriodMin;
 77→        this.baseSleepTimeMillis = baseSleepTimeMillis;
 78→        this.setRejectedExecutionHandler(rejectCounter);
 79→
 80→        this.taskCache = CacheBuilder.newBuilder().expireAfterWrite(3, TimeUnit.MINUTES)
 81→                // Invalidate entries that got executed by the threadPool and lost their
 82→                // reference
 83→                .weakValues().concurrencyLevel(threadsMaximum).build();
 84→    }
 85→
 86→    public void execute(KeyRunnable r) {
 87→        if (isShutdown.get()) {
 88→            logger.info(name + ": Task ignored, queue on hold or shutdown");
 89→            return;
 90→        }
 91→        if (taskCache.getIfPresent(r.getKey()) == null) {
 92→            taskCache.put(r.getKey(), r);
 93→            super.execute(r);
 94→        }
 95→    }
 96→
 97→    public long getRejectedTaskCount() {
 98→        return rejectCounter.getRejectCount();
 99→    }
100→
101→    /**
102→     * Monitor if the queue is unhealthy for MIN_UNHEALTHY_PERIOD_MIN
103→     *
104→     * If unhealthy, the service will start the shutdown process and the caller is responsible for
105→     * starting a new instance after the lock on awaitTermination is released.
106→     */
107→    protected boolean shutdownUnhealthy() throws InterruptedException {
108→        Date now = new Date();
109→        if (diffInMinutes(lastCheck, now) > minUnhealthyPeriodMin) {
110→            this.wasHealthy = healthCheck();
111→            this.lastCheck = now;
112→        }
113→
114→        if (healthCheck() || wasHealthy) {
115→            logger.debug(name + ": healthy (" + "Remaining Capacity: "
116→                    + this.getQueue().remainingCapacity() + ", Running: " + this.getActiveCount()
117→                    + ", Total Executed: " + this.getCompletedTaskCount() + ")");
118→            return true;
119→        } else if (isShutdown.get()) {
120→            logger.warn("Queue shutting down");
121→            return false;
122→        } else {
123→            logger.warn(name + ": unhealthy, starting shutdown)");
124→            threadDump();
125→
126→            isShutdown.set(true);
127→            super.shutdownNow();
128→            logger.warn(name + ": Awaiting unhealthy queue termination");
129→            if (super.awaitTermination(1, TimeUnit.MINUTES)) {
130→                logger.info(name + ": Terminated successfully");
131→            } else {
132→                logger.warn(name + ": Failed to terminate");
133→            }
134→            // Threads will eventually terminate, proceed
135→            taskCache.invalidateAll();
136→            return false;
137→        }
138→    }
139→
140→    private void threadDump() {
141→        ThreadMXBean mx = ManagementFactory.getThreadMXBean();
142→        for (ThreadInfo info : mx.dumpAllThreads(true, true)) {
143→            logger.debug(info.toString());
144→        }
145→    }
146→
147→    private static long diffInMinutes(Date dateStart, Date dateEnd) {
148→        return TimeUnit.MINUTES.convert(dateEnd.getTime() - dateStart.getTime(),
149→                TimeUnit.MILLISECONDS);
150→    }
151→
152→    /**
153→     * Lowers the sleep time as the queue grows.
154→     *
155→     * @return
156→     */
157→    public int sleepTime() {
158→        if (!isShutdown.get()) {
159→            int sleep = (int) (baseSleepTimeMillis
160→                    - (((this.getQueue().size() / (float) this.poolSize) * baseSleepTimeMillis))
161→                            * 2);
162→            if (sleep < 0) {
163→                sleep = 0;
164→            }
165→            return sleep;
166→        } else {
167→            return 0;
168→        }
169→    }
170→
171→    @Override
172→    protected void beforeExecute(Thread t, Runnable r) {
173→        super.beforeExecute(t, r);
174→        if (isShutdown()) {
175→            this.remove(r);
176→        } else {
177→            if (baseSleepTimeMillis > 0) {
178→                try {
179→                    Thread.sleep(sleepTime());
180→                } catch (InterruptedException e) {
181→                    logger.info(name + ": booking queue was interrupted.");
182→                }
183→            }
184→        }
185→    }
186→
187→    @Override
188→    protected void afterExecute(Runnable r, Throwable t) {
189→        super.afterExecute(r, t);
190→
191→        // Invalidate cache to avoid having to wait for GC to mark processed entries
192→        // collectible
193→        KeyRunnable h = (KeyRunnable) r;
194→        taskCache.invalidate(h.getKey());
195→    }
196→
197→    protected boolean healthCheck() {
198→        return (this.getQueue().remainingCapacity() > 0)
199→                || (getRejectedTaskCount() < this.poolSize / healthThreshold);
200→    }

