136→    /**
137→     * Handle the given FrameCompleteReport from RQD.
138→     *
139→     * @param report
140→     */
141→    public void handleFrameCompleteReport(final FrameCompleteReport report) {
142→
143→        /*
144→         * A boolean we're going to set to true if we can detect a corrupted data block in Oracle.
145→         */
146→        if (isShutdown()) {
147→            throw new RqdRetryReportException("Error processing the frame complete report, "
148→                    + "cuebot not accepting packets.");
149→        }
150→
151→        try {
152→            final VirtualProc proc = hostManager.getVirtualProc(report.getFrame().getResourceId());
153→            final DispatchJob job = jobManager.getDispatchJob(proc.getJobId());
154→            final LayerDetail layer = jobManager.getLayerDetail(report.getFrame().getLayerId());
155→            final FrameDetail frameDetail =
156→                    jobManager.getFrameDetail(report.getFrame().getFrameId());
157→            final DispatchFrame frame = jobManager.getDispatchFrame(report.getFrame().getFrameId());
158→            final FrameState newFrameState = determineFrameState(job, layer, frame, report);
159→            final String key = proc.getJobId() + "_" + report.getFrame().getLayerId() + "_"
160→                    + report.getFrame().getFrameId();
161→
162→            // rqd is currently not able to report exit_signal=9 when a frame is killed by
163→            // the OOM logic. The current solution sets exitStatus to
164→            // Dispatcher.EXIT_STATUS_MEMORY_FAILURE before killing the frame, this enables
165→            // auto-retrying frames affected by the logic when they report with a
166→            // frameCompleteReport. This status retouch ensures a frame complete report is
167→            // not able to override what has been set by the previous logic.
168→            int exitStatus = report.getExitStatus();
169→            if (frameDetail.exitStatus == Dispatcher.EXIT_STATUS_MEMORY_FAILURE) {
170→                exitStatus = frameDetail.exitStatus;
171→            }
172→
173→            if (dispatchSupport.stopFrame(frame, newFrameState, exitStatus,
174→                    report.getFrame().getMaxRss())) {
175→                if (dispatcher.isTestMode()) {
176→                    // Database modifications on a threadpool cannot be captured by the test thread
177→                    handlePostFrameCompleteOperations(proc, report, job, frame, newFrameState,
178→                            frameDetail);
179→                } else {
180→                    dispatchQueue.execute(new KeyRunnable(key) {
181→                        @Override
182→                        public void run() {
183→                            try {
184→                                handlePostFrameCompleteOperations(proc, report, job, frame,
185→                                        newFrameState, frameDetail);
186→                            } catch (Exception e) {
187→                                logger.warn("Exception during handlePostFrameCompleteOperations "
188→                                        + "in handleFrameCompleteReport"
189→                                        + CueExceptionUtil.getStackTrace(e));
190→                            }
191→                        }
192→                    });
193→                }
194→            } else {
195→                /*
196→                 * First check if we have a redirect. When a user retries a frame the proc is
197→                 * redirected back to the same job without checking any other properties.
198→                 */
199→                if (redirectManager.hasRedirect(proc)) {
200→                    dispatchQueue.execute(new KeyRunnable(key) {
201→                        @Override
202→                        public void run() {
203→                            try {
204→                                redirectManager.redirect(proc);
205→                            } catch (Exception e) {
206→                                logger.warn("Exception during redirect in handleFrameCompleteReport"
207→                                        + CueExceptionUtil.getStackTrace(e));
208→                            }
209→                        }
210→                    });
211→                } else {
212→                    dispatchQueue.execute(new KeyRunnable(key) {
213→                        @Override
214→                        public void run() {
215→                            try {
216→                                dispatchSupport.unbookProc(proc);
217→                            } catch (Exception e) {
218→                                logger.warn(
219→                                        "Exception during unbookProc in handleFrameCompleteReport"
220→                                                + CueExceptionUtil.getStackTrace(e));
221→                            }
222→                        }
223→                    });
224→                }
225→            }
226→        } catch (EmptyResultDataAccessException e) {
227→            /*
228→             * Do not propagate this exception to RQD. This usually means the cue lost connectivity
229→             * to the host and cleared out the record of the proc. If this is propagated back to
230→             * RQD, RQD will keep retrying the operation forever.
231→             */
232→            logger.info("failed to acquire data needed to " + "process completed frame: "
233→                    + report.getFrame().getFrameName() + " in job " + report.getFrame().getJobName()
234→                    + "," + e);
235→        } catch (Exception e) {
236→
237→            /*
238→             * Everything else we kick back to RQD.
239→             */
240→            logger.info("failed to acquire data needed " + "to process completed frame: "
241→                    + report.getFrame().getFrameName() + " in job " + report.getFrame().getJobName()
242→                    + "," + e);
243→
244→            throw new RqdRetryReportException("error processing the frame complete "
245→                    + "report, sending retry message to RQD " + e, e);
246→        }
247→    }
