100→     * more dispatch threads than booking threads, the dispatcher will over compensate and unbook

264→    public void handlePostFrameCompleteOperations(VirtualProc proc, FrameCompleteReport report,
265→            DispatchJob job, DispatchFrame frame, FrameState newFrameState,
266→            FrameDetail frameDetail) {
267→        try {
268→
269→            /*
270→             * Publish frame complete event to Kafka for monitoring
271→             */
272→            publishFrameCompleteEvent(report, frame, frameDetail, newFrameState, proc);
273→
274→            /*
275→             * The default behavior is to keep the proc on the same job.
276→             */
277→            boolean unbookProc = proc.unbooked;
278→
279→            dispatchSupport.updateUsageCounters(frame, report.getExitStatus());
280→
281→            boolean isLayerComplete = false;
282→
283→            if (newFrameState.equals(FrameState.SUCCEEDED) || (!satisfyDependOnlyOnFrameSuccess
284→                    && newFrameState.equals(FrameState.EATEN))) {
285→                jobManagerSupport.satisfyWhatDependsOn(frame);
286→                isLayerComplete = jobManager.isLayerComplete(frame);
287→                if (isLayerComplete) {
288→                    jobManagerSupport.satisfyWhatDependsOn((LayerInterface) frame);
289→
290→                    // Record layer max runtime and memory metrics
291→                    if (prometheusMetrics != null) {
292→                        ExecutionSummary layerSummary =
293→                                jobManager.getExecutionSummary((LayerInterface) frame);
294→                        LayerDetail layerDetail = jobManager.getLayerDetail(frame.getLayerId());
295→                        prometheusMetrics.recordLayerMaxRuntime(layerSummary.highFrameSec,
296→                                frame.show, frame.shot, layerDetail.type.toString());
297→                        if (layerSummary.highMemoryKb > 0) {
298→                            prometheusMetrics.recordLayerMaxMemory(
299→                                    layerSummary.highMemoryKb * 1024L, frame.show, frame.shot,
300→                                    layerDetail.type.toString());
301→                        }
302→                    }
303→
304→                    // Publish layer completed event to Kafka
305→                    if (kafkaEventPublisher != null && kafkaEventPublisher.isEnabled()) {
306→                        LayerDetail layerDetail = jobManager.getLayerDetail(frame.getLayerId());
307→                        LayerEvent layerEvent =
308→                                monitoringEventBuilder.buildLayerEvent(EventType.LAYER_COMPLETED,
309→                                        layerDetail, frame.getName(), frame.show);
310→                        kafkaEventPublisher.publishLayerEvent(layerEvent);
311→                    }
312→                }
313→            }
314→
315→            if (newFrameState.equals(FrameState.SUCCEEDED) && !isLayerComplete) {
316→                /*
317→                 * If the layer meets some specific criteria then try to update the minimum memory
318→                 * and tags so it can run on a wider variety of cores, namely older hardware.
319→                 */
320→                jobManager.optimizeLayer(frame, report.getFrame().getNumCores(),
321→                        report.getFrame().getMaxRss(), report.getRunTime());
322→            }
323→
324→            /*
325→             * The final frame can either be Succeeded or Eaten. If you only check if the frame is
326→             * Succeeded before doing an isJobComplete check, then jobs that finish with the
327→             * auto-eat flag enabled will not leave the cue.
328→             */
329→            if (newFrameState.equals(FrameState.SUCCEEDED)
330→                    || newFrameState.equals(FrameState.EATEN)) {
331→                if (jobManager.isJobComplete(job)) {
332→                    job.state = JobState.FINISHED;
333→                    jobManagerSupport.queueShutdownJob(job, new Source("natural"), false);
334→                }
335→            }
336→
337→            /*
338→             * Some exit statuses indicate that a frame was killed by the application due to a
339→             * memory issue and should be retried. In this case, disable the optimizer and raise the
340→             * memory by what is specified in the show's service override, service or 2GB.
341→             */
342→            if (report.getExitStatus() == Dispatcher.EXIT_STATUS_MEMORY_FAILURE
343→                    || report.getExitSignal() == Dispatcher.EXIT_STATUS_MEMORY_FAILURE
344→                    || frameDetail.exitStatus == Dispatcher.EXIT_STATUS_MEMORY_FAILURE
345→                    || report.getExitStatus() == Dispatcher.DOCKER_EXIT_STATUS_MEMORY_FAILURE) {
346→                long increase = CueUtil.GB2;
347→
348→                // since there can be multiple services, just going for the
349→                // first service (primary)
350→                String serviceName = "";
351→                try {
352→                    serviceName = frame.services.split(",")[0];
353→                    ServiceOverride showService = whiteboardDao
354→                            .getServiceOverride(showDao.findShowDetail(frame.show), serviceName);
355→                    // increase override is stored in Kb format so convert to Mb
356→                    // for easier reading. Note: Kb->Mb conversion uses 1024 blocks
357→                    increase = showService.getData().getMinMemoryIncrease();
358→                    logger.info("Using " + serviceName + " service show "
359→                            + "override for memory increase: " + Math.floor(increase / 1024)
360→                            + "Mb.");
361→                } catch (NullPointerException e) {
362→                    logger.info("Frame has no associated services");
363→                } catch (EmptyResultDataAccessException e) {
364→                    logger.info(frame.show + " has no service override for " + serviceName + ".");
365→                    Service service = whiteboardDao.findService(serviceName);
366→                    increase = service.getMinMemoryIncrease();
367→                    logger.info("Using service default for mem increase: "
368→                            + Math.floor(increase / 1024) + "Mb.");
369→                }
370→
371→                unbookProc = true;
372→                jobManager.enableMemoryOptimizer(frame, false);
373→                jobManager.increaseLayerMemoryRequirement(frame, proc.memoryReserved + increase);
374→                logger.info("Increased mem usage to: " + (proc.memoryReserved + increase));
375→            }
376→
377→            /*
378→             * Check for local dispatching.
379→             */
380→
381→            if (proc.isLocalDispatch) {
382→
383→                if (!bookingManager.hasLocalHostAssignment(proc)) {
384→                    logger.info("the proc " + proc + " no longer has a local assignment.");
385→                    unbookProc = true;
386→                }
387→            }
388→
389→            /*
390→             * An exit status of FAILED_LAUNCH (256) indicates that the frame could not be launched
391→             * due to some unforeseen unrecoverable error that is not checked when the launch
392→             * command is given. The most common cause of this is when the job log directory is
393→             * removed before the job is complete.
394→             *
395→             * Frames that return a 256 are put Frame back into WAITING status
396→             */
397→
398→            else if (report.getExitStatus() == FrameExitStatus.FAILED_LAUNCH_VALUE) {
399→                logger.info("unbooking " + proc + " frame status was failed frame launch.");
400→                unbookProc = true;
401→            }
402→
403→            else if (report.getHost().getNimbyLocked()) {
404→
405→                if (!proc.isLocalDispatch) {
406→                    logger.info("unbooking " + proc + " was NIMBY locked.");
407→                    unbookProc = true;
408→                }
409→
410→                /* Update the NIMBY locked state */
411→                hostManager.setHostLock(proc, LockState.NIMBY_LOCKED, new Source("NIMBY"));
412→            } else if (report.getHost().getFreeMem() < CueUtil.MB512) {
413→                /*
414→                 * Unbook anything on a proc that has only 512MB of free memory left.
415→                 */
416→                logger.info("unbooking" + proc + " was low was memory ");
417→                unbookProc = true;
418→            } else if (dispatchSupport.isShowOverBurst(proc)) {
419→                /*
420→                 * Unbook the proc if the show is over burst.
421→                 */
422→                logger.info("show using proc " + proc + " is over burst.");
423→                unbookProc = true;
424→            } else if (!hostManager.isHostUp(proc)) {
425→
426→                logger.info("the proc " + proc + " is not in the update state.");
427→                unbookProc = true;
428→            } else if (hostManager.isLocked(proc)) {
429→                if (!proc.isLocalDispatch) {
430→                    logger.info("the proc " + proc + " is not in the open state.");
431→                    unbookProc = true;
432→                }
433→            } else if (redirectManager.hasRedirect(proc)) {
434→
435→                logger.info("the proc " + proc + " has been redirected.");
436→
437→                if (redirectManager.redirect(proc)) {
438→                    return;
439→                }
440→            }
441→
442→            /*
443→             * If the proc is unbooked at this point, then unbook it and return.
444→             */
445→            if (unbookProc) {
446→                dispatchSupport.unbookProc(proc);
447→                return;
448→            }
449→
450→            /*
451→             * Check to see if the job the proc is currently assigned is still dispatchable.
452→             */
453→            if (job.state.equals(JobState.FINISHED)
454→                    || !dispatchSupport.isJobDispatchable(job, proc.isLocalDispatch)) {
455→
456→                logger.info("The " + job + " is no longer dispatchable.");
457→                dispatchSupport.unbookProc(proc);
458→
459→                /*
460→                 * Only rebook whole cores that have not been locally dispatched. Rebooking
461→                 * fractional can cause storms of booking requests that don't have a chance of
462→                 * finding a suitable frame to run.
463→                 */
464→                if (!proc.isLocalDispatch && proc.coresReserved >= 100
465→                        && dispatchSupport.isCueBookable(job)) {
466→
467→                    bookingQueue.execute(new DispatchBookHost(
468→                            hostManager.getDispatchHost(proc.getHostId()), dispatcher, env));
469→                }
470→
471→                if (job.state.equals(JobState.FINISHED)) {
472→                    jsmMover.send(job);
473→                }
474→                return;
475→            }
476→
477→            /*
478→             * If the job is marked unbookable and its over its minimum value, we check to see if
479→             * the proc can be moved to a job that hasn't reached its minimum proc yet.
480→             *
481→             * This will handle show balancing in the future.
482→             */
483→
484→            if (!proc.isLocalDispatch && randomNumber.nextInt(100) <= Dispatcher.UNBOOK_FREQUENCY
485→                    && System.currentTimeMillis() > lastUnbook.get()) {
486→
487→                // First make sure all jobs have their min cores
488→                // Then check for higher priority jobs
489→                // If not, rebook this job
490→                if (job.autoUnbook && proc.coresReserved >= 100) {
491→                    if (jobManager.isOverMinCores(job)) {
492→                        try {
493→
494→                            boolean unbook = dispatchSupport.findUnderProcedJob(job, proc);
495→
496→                            if (!unbook) {
497→                                JobDetail jobDetail = jobManager.getJobDetail(job.id);
498→                                unbook = dispatchSupport.higherPriorityJobExists(jobDetail, proc);
499→                            }
500→
501→                            if (unbook) {
502→
503→                                // Set a new time to allow unbooking.
504→                                lastUnbook.set(System.currentTimeMillis() + UNBOOK_EXPIRE_MS);
505→
506→                                logger.info("Transfering " + proc);
507→                                dispatchSupport.unbookProc(proc);
508→
509→                                DispatchHost host = hostManager.getDispatchHost(proc.getHostId());
510→
511→                                bookingQueue.execute(new DispatchBookHost(host, dispatcher, env));
512→                                return;
513→                            }
514→                        } catch (JobLookupException e) {
515→                            // wasn't able to find new job
516→                        }
517→                    }
518→                }
519→            }
520→
521→            if (newFrameState.equals(FrameState.WAITING)
522→                    || newFrameState.equals(FrameState.SUCCEEDED)) {
523→
524→                /*
525→                 * Check for stranded cores on the host.
526→                 */
527→                if (!proc.isLocalDispatch && dispatchSupport.hasStrandedCores(proc)
528→                        && jobManager.isLayerThreadable(frame)
529→                        && dispatchSupport.isJobBookable(job)) {
530→
531→                    int stranded_cores = hostManager.getStrandedCoreUnits(proc);
532→                    if (stranded_cores >= 100) {
533→
534→                        DispatchHost host = hostManager.getDispatchHost(proc.getHostId());
535→                        dispatchSupport.strandCores(host, stranded_cores);
536→                        dispatchSupport.unbookProc(proc);
537→                        bookingQueue.execute(new DispatchBookHost(host, job, dispatcher, env));
538→                        return;
539→                    }
540→                }
541→
542→                // Book the next frame of this job on the same proc
543→                if (proc.isLocalDispatch) {
544→                    dispatchQueue.execute(new DispatchNextFrame(job, proc, localDispatcher));
545→                } else {
546→                    dispatchQueue.execute(new DispatchNextFrame(job, proc, dispatcher));
547→                }
548→            } else {
549→                dispatchSupport.unbookProc(proc, "frame state was " + newFrameState.toString());
550→            }
551→        } catch (Exception e) {
552→            /*
553→             * At this point, the proc has no place to go. Since we've run into an error its best to
554→             * just unbook it. You can't handle this with a roll back because the record existed
555→             * before any transactions started.
556→             */
557→            logger.warn("An error occured when procssing " + "frame complete message, "
558→                    + CueExceptionUtil.getStackTrace(e));
559→            try {
560→                dispatchSupport.unbookProc(proc,
561→                        "an error occured when procssing frame complete message.");
562→            } catch (EmptyResultDataAccessException ee) {
563→                logger.info("Failed to find proc to unbook after frame " + "complete message "
564→                        + CueExceptionUtil.getStackTrace(ee));
565→            }
566→        }
567→    }
