569→    /**
570→     * Determines the new FrameState for a frame based on values contained in the
571→     * FrameCompleteReport
572→     *
573→     * If the frame is Waiting or Eaten, then it was manually set to that status before the frame
574→     * was killed. In that case whatever the current state in the DB is the one we want to use.
575→     *
576→     * If the frame status is dead or the frame.exitStatus is a non-zero value, and the frame has
577→     * been retried job.maxRetries times, then the frame is Dead. If the frame has an exit status of
578→     * 256, that is a non-retry status, the frame is dead.
579→     *
580→     * Assuming the two previous checks are not true, then a non-zero exit status sets the frame
581→     * back to Waiting, while a zero status sets the frame to Succeeded.
582→     *
583→     * @param job
584→     * @param frame
585→     * @param report
586→     * @return
587→     */
588→    public static final FrameState determineFrameState(DispatchJob job, LayerDetail layer,
589→            DispatchFrame frame, FrameCompleteReport report) {
590→
591→        if (EnumSet.of(FrameState.WAITING, FrameState.EATEN).contains(frame.state)) {
592→            return frame.state;
593→        }
594→        // Checks for frames that have reached max retries.
595→        else if (frame.state.equals(FrameState.DEAD)) {
596→            if (job.autoEat) {
597→                return FrameState.EATEN;
598→            } else {
599→                return FrameState.DEPEND;
600→            }
601→        } else if (report.getExitStatus() != 0) {
602→
603→            long r = System.currentTimeMillis() / 1000;
604→            long lastUpdate = (r - report.getFrame().getLluTime()) / 60;
605→
606→            FrameState newState = FrameState.WAITING;
607→            if (report.getExitStatus() == FrameExitStatus.SKIP_RETRY_VALUE
608→                    || (job.maxRetries != 0 && report.getExitSignal() == 119)) {
609→                report = FrameCompleteReport.newBuilder(report)
610→                        .setExitStatus(FrameExitStatus.SKIP_RETRY_VALUE).build();
611→                newState = FrameState.WAITING;
612→            } else if ((report.getExitStatus() == FrameExitStatus.FAILED_LAUNCH_VALUE
613→                    || report.getExitSignal() == FrameExitStatus.FAILED_LAUNCH_VALUE)
614→                    && (frame.retries < job.maxRetries)) {
615→                // exemption code 256
616→                report = FrameCompleteReport.newBuilder(report)
617→                        .setExitStatus(report.getExitStatus()).build();
618→                newState = FrameState.WAITING;
619→            } else if (report.getHost().getNimbyLocked() && report.getExitSignal() == 15) {
620→                // If frame got killed because the host was nimby locked,
621→                // retry even if retry count is higher than maxretrycount
622→                newState = FrameState.WAITING;
623→            } else if (job.autoEat) {
624→                newState = FrameState.EATEN;
625→                // ETC Time out and LLU timeout
626→            } else if (layer.timeout_llu != 0 && report.getFrame().getLluTime() != 0
627→                    && lastUpdate > (layer.timeout_llu - 1)) {
628→                newState = FrameState.DEAD;
629→            } else if (layer.timeout != 0 && report.getRunTime() > layer.timeout * 60) {
630→                newState = FrameState.DEAD;
631→            } else if (report.getRunTime() > Dispatcher.FRAME_TIME_NO_RETRY) {
632→                newState = FrameState.DEAD;
633→            } else if (frame.retries >= job.maxRetries) {
634→                if (!(report.getExitStatus() == Dispatcher.EXIT_STATUS_MEMORY_FAILURE
635→                        || report.getExitSignal() == Dispatcher.EXIT_STATUS_MEMORY_FAILURE
636→                        || report.getExitStatus() == Dispatcher.DOCKER_EXIT_STATUS_MEMORY_FAILURE))
